def is_safe_ip(ip_str):
    """Return True if ip_str is a safe IPv4 address, False otherwise."""
    try:
        ip = ipaddress.ip_address(ip_str)
        # Block IPv6 entirely
        if ip.version == 6:
            return False
        # Check against dangerous networks
        for network in DANGEROUS_NETWORKS:
            if ip in network:
                return False
        return True
    except ValueError:
        return False

def resolve_and_validate(url):
    """Resolve hostname from URL and validate all resolved IPs."""
    parsed = urlparse(url)
    hostname = parsed.hostname
    if not hostname:
        return False

    try:
        # Resolve to all IP addresses (IPv4 and IPv6)
        addr_info = socket.getaddrinfo(hostname, None, socket.AF_UNSPEC, socket.SOCK_STREAM)
        for info in addr_info:
            ip_str = info[4][0]
            # Reject IPv6
            if ':' in ip_str:
                return False
            if not is_safe_ip(ip_str):
                return False
        return True
    except (socket.gaierror, OSError):
        return False

